// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [selectedForecastIndex, setSelectedForecastIndex] = useState<number>(0);

  const normalizedCondition = useMemo(() => {
    return (props.condition || '').toLowerCase();
  }, [props.condition]);

  const conditionIcon = useMemo(() => {
    if (normalizedCondition.includes('sun') || normalizedCondition.includes('clear')) return '☀️';
    if (normalizedCondition.includes('cloud')) return '☁️';
    if (normalizedCondition.includes('rain') || normalizedCondition.includes('drizzle')) return '🌧️';
    if (normalizedCondition.includes('storm') || normalizedCondition.includes('thunder')) return '⛈️';
    if (normalizedCondition.includes('snow') || normalizedCondition.includes('blizzard')) return '❄️';
    if (normalizedCondition.includes('mist') || normalizedCondition.includes('fog')) return '🌫️';
    if (normalizedCondition.includes('wind')) return '💨';
    return '🌤️';
  }, [normalizedCondition]);

  useEffect(() => {
    if (!props.forecast || props.forecast.length === 0) {
      setSelectedForecastIndex(0);
      return;
    }
    if (selectedForecastIndex > props.forecast.length - 1) {
      setSelectedForecastIndex(0);
    }
  }, [props.forecast, selectedForecastIndex]);

  const selectedForecast = useMemo(() => {
    if (!props.forecast || props.forecast.length === 0) return null;
    return props.forecast[selectedForecastIndex] || props.forecast[0] || null;
  }, [props.forecast, selectedForecastIndex]);

  const forecastSlots = useMemo(() => {
    return Array.from({ length: 5 }, (_, index) => props.forecast[index] || null);
  }, [props.forecast]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-6)"
        shadow="md"
        radius="xl"
      >
        <Stack gap="var(--ggui-spacing-6)">
          <Row justify="between" align="start" wrap>
            <Stack gap="var(--ggui-spacing-2)">
              <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                Current Weather
              </Text>
              <Heading level={2} color="var(--ggui-color-onSurface)">
                {props.city}
              </Heading>
              <Row align="center" gap="var(--ggui-spacing-2)">
                <Text size="4xl" weight="bold" color="var(--ggui-color-primary-700)">
                  {props.temperature}°{props.unit}
                </Text>
                <Text size="3xl" is="span" aria-label={props.condition}>
                  {conditionIcon}
                </Text>
              </Row>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
                {props.condition}
              </Text>
            </Stack>

            <Card
              padding="var(--ggui-spacing-4)"
              shadow="sm"
              radius="lg"
              border
            >
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={5}>Details</Heading>
                <Row align="center" gap="var(--ggui-spacing-2)">
                  <Icon name="droplets" size={18} color="var(--ggui-color-primary-600)" />
                  <Text variant="label">Humidity</Text>
                  <Spacer size="flex" />
                  <Text color="var(--ggui-color-onSurfaceVariant)">{props.humidity}%</Text>
                </Row>
                <Row align="center" gap="var(--ggui-spacing-2)">
                  <Icon name="wind" size={18} color="var(--ggui-color-primary-600)" />
                  <Text variant="label">Wind Speed</Text>
                  <Spacer size="flex" />
                  <Text color="var(--ggui-color-onSurfaceVariant)">{props.windSpeed}</Text>
                </Row>
                {selectedForecast && (
                  <>
                    <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      Selected day: {selectedForecast.day || 'N/A'}
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      High: {selectedForecast.high ?? 'N/A'}°{props.unit} · Low: {selectedForecast.low ?? 'N/A'}°{props.unit}
                    </Text>
                  </>
                )}
              </Stack>
            </Card>
          </Row>

          <Divider margin="var(--ggui-spacing-1)" color="var(--ggui-color-outlineVariant)" />

          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={5} color="var(--ggui-color-onSurface)">
              5-Day Forecast
            </Heading>

            {(!props.forecast || props.forecast.length === 0) && (
              <Alert variant="info" title="No forecast available">
                Forecast data is currently unavailable.
              </Alert>
            )}

            <Row gap="var(--ggui-spacing-3)" wrap>
              {forecastSlots.map((item, index) => (
                <Card
                  key={`${item?.day || 'day'}-${index}`}
                  as={Clickable}
                  onClick={() => {
                    if (item) setSelectedForecastIndex(index);
                  }}
                  padding="var(--ggui-spacing-3)"
                  radius="lg"
                  shadow="sm"
                  border
                  hoverStyle={{ opacity: item ? 0.9 : 1 }}
                >
                  <Stack gap="var(--ggui-spacing-2)" align="center">
                    <Text variant="label" color="var(--ggui-color-onSurface)">
                      {item?.day || 'N/A'}
                    </Text>
                    <Text size="2xl" is="span" aria-label={item?.icon || 'weather icon'}>
                      {item?.icon || '🌤️'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      {item?.high ?? 'N/A'}°{props.unit} / {item?.low ?? 'N/A'}°{props.unit}
                    </Text>
                    {item && selectedForecastIndex === index && <Badge variant="primary" size="sm">Selected</Badge>}
                  </Stack>
                </Card>
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Container>

  );
}

