// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const totalSteps = 5;
  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<number>(0);
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [touchedName, setTouchedName] = useState<boolean>(false);
  const [touchedEmail, setTouchedEmail] = useState<boolean>(false);
  const emailRegex = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/, []);

  const nameError = touchedName && name.trim().length === 0 ? 'Name is required.' : '';
  const emailError = touchedEmail && email.trim().length === 0
    ? 'Email is required.'
    : touchedEmail && !emailRegex.test(email.trim())
      ? 'Please enter a valid email address.'
      : '';

  const satisfactionOptions = useMemo(() => {
    return (props.satisfactionLabels || []).map((label, index) => ({
      value: String(index + 1),
      label,
    }));
  }, [props.satisfactionLabels]);

  const isStepValid = useMemo(() => {
    if (step === 1) {
      return name.trim().length > 0 && emailRegex.test(email.trim());
    }
    if (step === 2) {
      return satisfaction >= 1 && satisfaction <= 5;
    }
    if (step === 3) {
      return true;
    }
    if (step === 4) {
      return comments.length <= 500;
    }
    return true;
  }, [step, name, email, satisfaction, comments, emailRegex]);

  const progressValue = useMemo(() => (step / totalSteps) * 100, [step]);

  const toggleFeature = useCallback((option: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(option)) return prev;
        return [...prev, option];
      }
      return prev.filter((item) => item !== option);
    });
  }, []);

  const goNext = useCallback(() => {
    if (step === 1) {
      setTouchedName(true);
      setTouchedEmail(true);
    }
    if (!isStepValid) return;
    setStep((prev) => (prev < totalSteps ? prev + 1 : prev));
  }, [step, isStepValid]);

  const goBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction,
      features,
      comments: comments.trim(),
    });
  }, [submit, name, email, satisfaction, features, comments]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" shadow="sm" border radius="lg">
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={3}>Survey</Heading>
              <Badge variant="primary">Step {step} of {totalSteps}</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" variant="default" />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Tell us about yourself</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  error={nameError}
                  placeholder="Enter your name"
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  error={emailError}
                  placeholder="you@example.com"
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>How satisfied are you?</Heading>
                <RadioGroup
                  label="Satisfaction rating"
                  value={satisfaction > 0 ? String(satisfaction) : ''}
                  onChange={(value) => setSatisfaction(Number(value))}
                  options={satisfactionOptions}
                  direction="vertical"
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Which features interest you?</Heading>
                {(props.featureOptions || []).length === 0 ? (
                  <Alert variant="info" title="No feature options available">
                    There are currently no feature options to choose from.
                  </Alert>
                ) : (
                  <Stack gap="var(--ggui-spacing-2)">
                    {(props.featureOptions || []).map((option) => (
                      <Checkbox
                        key={option}
                        label={option}
                        checked={features.includes(option)}
                        onChange={(checked) => toggleFeature(option, checked)}
                      />
                    ))}
                  </Stack>
                )}
              </Stack>
            )}

            {step === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Additional comments</Heading>
                <TextArea
                  label="Comments (optional)"
                  value={comments}
                  onChange={setComments}
                  rows={6}
                  maxLength={500}
                  showCount
                  helperText="Share anything else you'd like us to know."
                />
              </Stack>
            )}

            {step === 5 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review your responses</Heading>
                <Card padding="var(--ggui-spacing-4)" border shadow="none" radius="md">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row justify="between"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Row justify="between"><Text variant="label">Satisfaction</Text><Text>{satisfaction > 0 ? `${satisfaction} - ${(props.satisfactionLabels || [])[satisfaction - 1] || ''}` : '-'}</Text></Row>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label">Feature interests</Text>
                      {features.length === 0 ? (
                        <Text color="var(--ggui-color-onSurfaceVariant)">None selected</Text>
                      ) : (
                        <Row wrap gap="var(--ggui-spacing-2)">
                          {features.map((feature) => (
                            <Tag key={feature} variant="primary">{feature}</Tag>
                          ))}
                        </Row>
                      )}
                    </Stack>
                    <Divider margin="var(--ggui-spacing-1)" />
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label">Comments</Text>
                      <Text color="var(--ggui-color-onSurfaceVariant)">{comments.trim().length > 0 ? comments : 'No comments provided'}</Text>
                    </Stack>
                  </Stack>
                </Card>
              </Stack>
            )}

            <Divider margin="var(--ggui-spacing-2)" />

            <Row justify="between" align="center">
              <Button variant="outline" onPress={goBack} disabled={step === 1}>
                Back
              </Button>
              {step < totalSteps ? (
                <Button variant="primary" onPress={goNext} disabled={!isStepValid}>
                  Next
                </Button>
              ) : (
                <Button variant="primary" onPress={handleSubmit}>
                  Submit survey
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

