import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: Record<string, unknown> };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string; updatedAt?: number; clientRequestId?: string } };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [boardTasks, setBoardTasks] = useState<Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string; updatedAt: number; clientRequestId?: string }>>([]);
  const [addFormByColumn, setAddFormByColumn] = useState<Record<string, boolean>>({});
  const [newTaskTitleByColumn, setNewTaskTitleByColumn] = useState<Record<string, string>>({});
  const [newTaskPriorityByColumn, setNewTaskPriorityByColumn] = useState<Record<string, 'low' | 'medium' | 'high'>>({});
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');
  const localVersionRef = useRef<Record<string, number>>({});

  const normalizeTask = useCallback(
    (
      task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string; clientRequestId?: string },
      fallbackId: string
    ) => ({
      id: task.id || fallbackId,
      title: task.title || 'Untitled task',
      priority: task.priority || 'medium',
      assignee: task.assignee || 'NA',
      column: task.column || 'todo',
      dueDate: task.dueDate,
      clientRequestId: task.clientRequestId,
    }),
    []
  );

  useEffect(() => {
    const incoming = (props.tasks || []).map((task, index) => normalizeTask(task, `task-${index}-${task.title || 'untitled'}`));
    setBoardTasks((prev) => {
      const next = [...prev];
      incoming.forEach((task) => {
        const idx = next.findIndex((t) => t.id === task.id);
        const localVersion = localVersionRef.current[task.id] || 0;
        if (idx === -1) {
          next.push({ ...task, updatedAt: Date.now() });
        } else if (localVersion === 0) {
          next[idx] = { ...next[idx], ...task, updatedAt: Date.now() };
        }
      });
      return next;
    });
  }, [props.tasks, normalizeTask]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) return;
    const incoming = taskChanged.latest.task;
    const incomingId = incoming.id || '';
    const streamAction = taskChanged.latest.action || 'edit';
    const incomingVersion = typeof incoming.updatedAt === 'number' ? incoming.updatedAt : 0;

    if (!incomingId && streamAction !== 'create') return;

    if (streamAction === 'delete' && incomingId) {
      setBoardTasks((prev) => prev.filter((t) => t.id !== incomingId));
      delete localVersionRef.current[incomingId];
      return;
    }

    setBoardTasks((prev) => {
      if (streamAction === 'create') {
        const normalizedCreated = {
          ...normalizeTask(incoming, incomingId || `task-stream-${Date.now()}`),
          updatedAt: incomingVersion,
        };

        const byId = prev.findIndex((t) => t.id === normalizedCreated.id);
        if (byId !== -1) {
          const localVersion = localVersionRef.current[normalizedCreated.id] || 0;
          if (localVersion > normalizedCreated.updatedAt) return prev;
          delete localVersionRef.current[normalizedCreated.id];
          return prev.map((t) => (t.id === normalizedCreated.id ? { ...t, ...normalizedCreated } : t));
        }

        const tempByRequestId = normalizedCreated.clientRequestId
          ? prev.findIndex((t) => t.clientRequestId === normalizedCreated.clientRequestId)
          : -1;
        if (tempByRequestId !== -1) {
          const tempId = prev[tempByRequestId].id;
          delete localVersionRef.current[tempId];
          delete localVersionRef.current[normalizedCreated.id];
          return prev.map((t, i) => (i === tempByRequestId ? { ...t, ...normalizedCreated } : t));
        }

        return [...prev, normalizedCreated];
      }

      const normalizedIncoming = { ...normalizeTask(incoming, incomingId), updatedAt: incomingVersion };
      const existingIndex = prev.findIndex((t) => t.id === normalizedIncoming.id);
      if (existingIndex === -1) {
        return prev;
      }
      const localVersion = localVersionRef.current[normalizedIncoming.id] || 0;
      if (localVersion > normalizedIncoming.updatedAt) return prev;
      delete localVersionRef.current[normalizedIncoming.id];
      return prev.map((t) => (t.id === normalizedIncoming.id ? { ...t, ...normalizedIncoming } : t));
    });
  }, [taskChanged.latest, normalizeTask]);

  const totalTasks = boardTasks.length;
  const doneColumnId = useMemo(() => {
    const found = [
      { id: 'todo', name: 'To Do' },
      { id: 'in-progress', name: 'In Progress' },
      { id: 'done', name: 'Done' },
    ].find((column) => (column.name || '').toLowerCase() === 'done');
    return found?.id || 'done';
  }, []);
  const completedCount = boardTasks.filter((task) => task.column === doneColumnId).length;

  const priorityVariant = useCallback((priority: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' => {
    if (priority === 'high') return 'error';
    if (priority === 'medium') return 'warning';
    return 'success';
  }, []);

  const moveTask = useCallback(
    (taskId: string, nextColumn: string) => {
      if (!nextColumn) return;
      const existing = boardTasks.find((task) => task.id === taskId);
      if (!existing || existing.column === nextColumn) return;
      const version = Date.now();
      localVersionRef.current[taskId] = version;
      setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: nextColumn, updatedAt: version } : task)));
      taskUpdate({ action: 'move', taskId, data: { column: nextColumn } });
    },
    [taskUpdate, boardTasks]
  );

  const startEditTask = useCallback((taskId: string, title: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(title);
  }, []);

  const saveEditTask = useCallback(
    (taskId: string) => {
      const nextTitle = editingTitle.trim();
      if (!nextTitle) return;
      const version = Date.now();
      localVersionRef.current[taskId] = version;
      setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: nextTitle, updatedAt: version } : task)));
      taskUpdate({ action: 'edit', taskId, data: { title: nextTitle } });
      setEditingTaskId('');
      setEditingTitle('');
    },
    [editingTitle, taskUpdate]
  );

  const cancelEditTask = useCallback(() => {
    setEditingTaskId('');
    setEditingTitle('');
  }, []);

  const addTask = useCallback(
    (columnId: string) => {
      const title = (newTaskTitleByColumn[columnId] || '').trim();
      const priority = newTaskPriorityByColumn[columnId] || 'medium';
      if (!title) return;
      const todoColumnId = 'todo';
      const requestId = `req-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
      const id = `temp-${requestId}`;
      const version = Date.now();
      const created = {
        id,
        title,
        priority,
        assignee: 'NA',
        column: todoColumnId,
        dueDate: undefined,
        updatedAt: version,
        clientRequestId: requestId,
      };
      localVersionRef.current[id] = version;
      setBoardTasks((prev) => [...prev, created]);
      taskUpdate({
        action: 'create',
        taskId: requestId,
        data: {
          title: created.title,
          priority: created.priority,
          assignee: created.assignee,
          column: created.column,
          dueDate: created.dueDate,
          clientRequestId: requestId,
        },
      });
      setNewTaskTitleByColumn((prev) => ({ ...prev, [columnId]: '' }));
      setNewTaskPriorityByColumn((prev) => ({ ...prev, [columnId]: 'medium' }));
      setAddFormByColumn((prev) => ({ ...prev, [columnId]: false }));
    },
    [newTaskTitleByColumn, newTaskPriorityByColumn, props.columns, taskUpdate]
  );

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3}>Kanban Board</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Live updates received: {taskChanged.all.length}
              </Text>
            </Stack>
            <Row gap="var(--ggui-spacing-3)" align="center">
              <Badge variant="primary">Total: {totalTasks}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
            </Row>
          </Row>
        </Card>

        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {[
            { id: 'todo', name: 'To Do' },
            { id: 'in-progress', name: 'In Progress' },
            { id: 'done', name: 'Done' },
          ].map((column) => {
              const columnId = column.id || 'unknown';
              const tasksInColumn = boardTasks.filter((task) => task.column === columnId);
              return (
                <Card
                  key={columnId}
                  padding="var(--ggui-spacing-4)"
                  shadow="sm"
                  border
                >
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row justify="between" align="center">
                      <Heading level={5}>{column.name || 'Untitled Column'}</Heading>
                      <Badge variant="default">{tasksInColumn.length}</Badge>
                    </Row>

                    <Stack gap="var(--ggui-spacing-3)">
                      {tasksInColumn.length === 0 ? (
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                          No tasks yet
                        </Text>
                      ) : (
                        tasksInColumn.map((task) => (
                          <Card key={task.id} padding="var(--ggui-spacing-3)" shadow="none" border>
                            <Stack gap="var(--ggui-spacing-2)">
                              {editingTaskId === task.id ? (
                                <Stack gap="var(--ggui-spacing-2)">
                                  <Input
                                    label="Edit task title"
                                    value={editingTitle}
                                    onChange={setEditingTitle}
                                    placeholder="Task title"
                                  />
                                  <Row gap="var(--ggui-spacing-2)">
                                    <Button size="sm" onPress={() => saveEditTask(task.id)}>Save</Button>
                                    <Button variant="ghost" size="sm" onPress={cancelEditTask}>Cancel</Button>
                                  </Row>
                                </Stack>
                              ) : (
                                <Text
                                  as={Clickable}
                                  onDoubleClick={() => startEditTask(task.id, task.title)}
                                  variant="label"
                                  color="var(--ggui-color-onSurface)"
                                >
                                  {task.title}
                                </Text>
                              )}

                              <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                                <Badge variant={priorityVariant(task.priority)}>{task.priority}</Badge>
                                <Avatar name={task.assignee} size="sm" />
                                {task.dueDate ? (
                                  <Tag variant="default">Due: {task.dueDate}</Tag>
                                ) : (
                                  <Tag variant="default">No due date</Tag>
                                )}
                              </Row>

                              <Select
                                label="Move task"
                                value={task.column}
                                onChange={(value) => moveTask(task.id, value)}
                                options={[
                                  { value: 'todo', label: 'To Do' },
                                  { value: 'in-progress', label: 'In Progress' },
                                  { value: 'done', label: 'Done' },
                                ]}
                              />
                              <Button variant="outline" size="sm" onPress={() => startEditTask(task.id, task.title)}>Edit</Button>
                            </Stack>
                          </Card>
                        ))
                      )}
                    </Stack>

                    {addFormByColumn[columnId] ? (
                      <Card padding="var(--ggui-spacing-3)" shadow="none" border>
                        <Stack gap="var(--ggui-spacing-2)">
                          <Input
                            label="Task title"
                            value={newTaskTitleByColumn[columnId] || ''}
                            onChange={(value) => setNewTaskTitleByColumn((prev) => ({ ...prev, [columnId]: value }))}
                            placeholder="Enter task title"
                          />
                          <Select
                            label="Priority"
                            value={newTaskPriorityByColumn[columnId] || 'medium'}
                            onChange={(value) => setNewTaskPriorityByColumn((prev) => ({ ...prev, [columnId]: (value as 'low' | 'medium' | 'high') }))}
                            options={[
                              { value: 'low', label: 'Low' },
                              { value: 'medium', label: 'Medium' },
                              { value: 'high', label: 'High' },
                            ]}
                          />
                          <Row gap="var(--ggui-spacing-2)">
                            <Button size="sm" onPress={() => addTask(columnId)}>Create Task</Button>
                            <Button
                              variant="ghost"
                              size="sm"
                              onPress={() => setAddFormByColumn((prev) => ({ ...prev, [columnId]: false }))}
                            >
                              Cancel
                            </Button>
                          </Row>
                        </Stack>
                      </Card>
                    ) : null}

                    <Button
                      variant="secondary"
                      onPress={() => {
                        setAddFormByColumn((prev) => ({ ...prev, [columnId]: true }));
                        setNewTaskPriorityByColumn((prev) => ({ ...prev, [columnId]: prev[columnId] || 'medium' }));
                        setNewTaskTitleByColumn((prev) => ({ ...prev, [columnId]: prev[columnId] || '' }));
                      }}
                    >
                      Add Task
                    </Button>
                  </Stack>
                </Card>
              );
            })}
          </Row>

      </Stack>
    </Container>

  );
}

