  lanthanide: 'var(--ggui-color-success-100)',
  actinide: 'var(--ggui-color-error-100)',
};

function getCategoryColor(category?: string): string {
  if (!category) return 'var(--ggui-color-surfaceVariant)';
  const normalized = category.toLowerCase().replace(/[-_]+/g, ' ').trim();
  return CATEGORY_COLORS[normalized] ?? 'var(--ggui-color-surfaceVariant)';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [search, setSearch] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const filteredElements = useMemo(() => {
    const list = Array.isArray(props.elements) ? props.elements : [];
    const query = search.trim().toLowerCase();
    if (!query) return list;
    return list.filter((element) => {
      const name = (element.name ?? '').toLowerCase();
      const symbol = (element.symbol ?? '').toLowerCase();
      return name.includes(query) || symbol.includes(query);
    });
  }, [props.elements, search]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) return null;
    const allElements = Array.isArray(props.elements) ? props.elements : [];
    return allElements.find((element) => element.atomicNumber === selectedAtomicNumber) ?? null;
  }, [props.elements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    (Array.isArray(props.elements) ? props.elements : []).forEach((element) => {
      if (element.category && element.category.trim()) {
        set.add(element.category);
      }
    });
    return Array.from(set).sort((a, b) => a.localeCompare(b));
  }, [props.elements]);

  return (
