          onChange={setSearch}
        />

        {!Array.isArray(props.elements) || props.elements.length === 0 ? (
          <Alert variant="info" title="No element data">
            No elements available to display.
          </Alert>
        ) : (
          <Card padding="var(--ggui-spacing-4)">
