                paddingBottom: 'var(--ggui-spacing-2)',
              }}
            >
              {filteredElements.length === 0 ? (
                <Box padding="var(--ggui-spacing-4)" style={{ gridColumn: '1 / span 18' }}>
                  <Text color="var(--ggui-color-onSurfaceVariant)">
                    No elements match your search.
                  </Text>
                </Box>
              ) : (
                filteredElements.map((element, index) => (
                  <Card
                    key={`${element.atomicNumber ?? index}-${element.symbol ?? index}`}
                    as={Clickable}
                    onClick={() => setSelectedAtomicNumber(element.atomicNumber ?? null)}
                    padding="var(--ggui-spacing-2)"
                    border
                    radius="md"
                    style={{
                      gridColumn: `${element.col ?? 1}`,
                      gridRow: `${element.row ?? 1}`,
                      minHeight: '72px',
