                      borderColor:
                        selectedElement?.atomicNumber === element.atomicNumber
                          ? 'var(--ggui-color-primary-600)'
                          : 'var(--ggui-color-outline)',
                      borderWidth:
                        selectedElement?.atomicNumber === element.atomicNumber ? '2px' : '1px',
                      borderStyle: 'solid',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        {element.atomicNumber ?? '-'}
                      </Text>
                      <Text align="center" size="xl" weight="bold">
                        {element.symbol ?? '?'}
                      </Text>
                    </Stack>
                  </Card>
                ))
              )}
            </Box>
          </Card>
        )}

        <Card padding="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4}>Element Details</Heading>
            {selectedElement ? (
              <Stack gap="var(--ggui-spacing-1)">
                <Text><Text is="span" weight="semibold">Name: </Text>{selectedElement.name ?? '-'}</Text>
                <Text><Text is="span" weight="semibold">Symbol: </Text>{selectedElement.symbol ?? '-'}</Text>
                <Text><Text is="span" weight="semibold">atomicNumber: </Text>{selectedElement.atomicNumber ?? '-'}</Text>
                <Text><Text is="span" weight="semibold">atomicWeight: </Text>{selectedElement.atomicWeight ?? '-'}</Text>
