}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }
  const [activeTab, setActiveTab] = useState<string>('description');
  const initialQuantity = 1;
  const [quantity, setQuantity] = useState<number>(initialQuantity);

  useEffect(() => {
    setQuantity((previous) => {
      const maxAllowed = Math.max(1, props.product.stock ?? 1);
      if (previous < 1) {
        return 1;
      }
      if (previous > maxAllowed) {
        return maxAllowed;
      }
      return previous;
    });
  }, [props.product.stock]);

  const safeStock = props.product.stock ?? 0;
  const safeRating = Math.max(0, Math.min(5, Math.round(props.product.rating ?? 0)));
  const isOutOfStock = safeStock <= 0;
  const isLowStock = safeStock > 0 && safeStock <= 5;
  const canIncrease = safeStock > 0 && quantity < safeStock;
  const canDecrease = quantity > 1;

  const formattedPrice = useMemo(() => {
    const amount = props.product.price ?? 0;
    const currency = props.product.currency ?? 'USD';
    try {
      return new Intl.NumberFormat(undefined, { style: 'currency', currency }).format(amount);
    } catch (_error) {
      return `${currency} ${amount.toFixed(2)}`;
    }
  }, [props.product.price, props.product.currency]);

  const specificationRows = useMemo(() => {
    return (props.product.specifications ?? []).map((item, index) => {
      if (typeof item === 'object' && item !== null && !Array.isArray(item)) {
        const record = item as Record<string, unknown>;
        if ('key' in record && 'value' in record) {
          return {
            id: `${String(record.key)}-${index}`,
            key: String(record.key ?? ''),
            value: String(record.value ?? ''),
          };
        }
        const firstKey = Object.keys(record)[0] ?? `Specification ${index + 1}`;
        return {
          id: `${firstKey}-${index}`,
          key: String(firstKey),
          value: String(record[firstKey] ?? ''),
        };
      }
      return {
        id: `spec-${index}`,
        key: `Specification ${index + 1}`,
        value: String(item ?? ''),
      };
    });
  }, [props.product.specifications]);

  const reviewItems = useMemo(() => {
    return (props.product.reviews ?? []).map((item, index) => {
      if (typeof item === 'object' && item !== null && !Array.isArray(item)) {
        const record = item as Record<string, unknown>;
        const ratingValue = Math.max(0, Math.min(5, Math.round(Number(record.rating ?? 0))));
        return {
          id: String(record.id ?? `review-${index}`),
          author: String(record.author ?? 'Anonymous'),
          rating: ratingValue,
          text: String(record.text ?? ''),
          date: String(record.date ?? ''),
        };
      }
      return {
        id: `review-${index}`,
        author: 'Anonymous',
        rating: 0,
        text: String(item ?? ''),
        date: '',
      };
    });
  }, [props.product.reviews]);

  const handleIncrement = useCallback(() => {
    if (!canIncrease) {
      return;
    }
    setQuantity((previous) => Math.min(previous + 1, safeStock));
  }, [canIncrease, safeStock]);

  const handleDecrement = useCallback(() => {
    if (!canDecrease) {
      return;
    }
    setQuantity((previous) => Math.max(1, previous - 1));
  }, [canDecrease]);

  const handleAddToCart = useCallback(() => {
    if (safeStock <= 0 || !props.product.id) {
      return;
    }
    const clampedQuantity = Math.min(Math.max(quantity, 1), safeStock);
    addToCart({
      productId: String(props.product.id),
      quantity: clampedQuantity,
    });
  }, [addToCart, props.product.id, quantity, safeStock]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Box
              background="var(--ggui-color-primary-50)"
              borderRadius="var(--ggui-shape-radius-lg)"
              padding="var(--ggui-spacing-6)"
            >
              <Stack gap="var(--ggui-spacing-6)">
                <Box
                  style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
                    gap: 'var(--ggui-spacing-6)',
                    alignItems: 'stretch',
                  }}
                >
                  <Box
                    background="var(--ggui-color-primary-100)"
                    borderRadius="var(--ggui-shape-radius-lg)"
                    padding="var(--ggui-spacing-8)"
                    style={{
                      minHeight: '280px',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      border: '1px solid var(--ggui-color-outlineVariant)',
                      textAlign: 'center',
                    }}
                  >
                    <Text size="xl" weight="semibold" color="var(--ggui-color-primary-700)">
                      {props.product.name ?? 'Unnamed Product'}
                    </Text>
                  </Box>

                  <Stack gap="var(--ggui-spacing-3)" justify="center">
                    <Heading level={2}>{props.product.name ?? 'Unnamed Product'}</Heading>
                    <Text size="2xl" weight="bold" color="var(--ggui-color-primary-700)">
                      {formattedPrice}
                    </Text>

                    <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                      <Row gap="var(--ggui-spacing-1)" align="center">
                        {[0, 1, 2, 3, 4].map((star) => (
                          <Text
                            key={`star-${star}`}
>
                            {star < safeRating ? '★' : '☆'}
                          </Text>
                        ))}
                      </Row>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        ({String(props.product.reviewCount ?? reviewItems.length)} reviews)
                      </Text>
                    </Row>

                    <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                      {isOutOfStock ? (
                        <Badge variant="error">Out of Stock</Badge>
                      ) : isLowStock ? (
                        <Badge variant="warning">Low Stock</Badge>
                      ) : (
                        <Badge variant="success">In Stock</Badge>
                      )}
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        {safeStock} available
                      </Text>
                    </Row>
                  </Stack>
                </Box>
              </Stack>
            </Box>

            <Tabs
              activeKey={activeTab}
              onChange={setActiveTab}
              variant="line"
              items={[
                {
                  key: 'description',
                  label: 'Description',
                  content: (
                    <Box paddingY="var(--ggui-spacing-2)">
