// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag
  const [allMessages, setAllMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages ?? []);
  const [draft, setDraft] = useState<string>('');
  const [typingState, setTypingState] = useState<StreamTyping | null>(null);
  const listRef = useRef<HTMLDivElement | null>(null);
  const isUserPinnedToBottomRef = useRef<boolean>(true);
  const hasInitiallyScrolledRef = useRef<boolean>(false);

  useEffect(() => {
    setAllMessages(props.messages ?? []);
  }, [props.messages]);

  useEffect(() => {
    const unsubscribeMessage = () => {};
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest as StreamMessage]);
    }
    return () => {
      unsubscribeMessage();
    };
  }, [message]);

  useEffect(() => {
    const unsubscribeTyping = () => {};
    setTypingState(typing.latest ?? null);
    return () => {
      unsubscribeTyping();
      setTypingState(null);
    };
  }, [typing]);

  useLayoutEffect(() => {
    if (!listRef.current) return;
    const list = listRef.current;
    if (!hasInitiallyScrolledRef.current) {
      list.scrollTop = list.scrollHeight;
      hasInitiallyScrolledRef.current = true;
      isUserPinnedToBottomRef.current = true;
      return;
    }
    if (isUserPinnedToBottomRef.current) {
      list.scrollTop = list.scrollHeight;
    }
  }, [allMessages]);

  useEffect(() => {
    if (!listRef.current) return;
    const list = listRef.current;
    const handleScroll = () => {
      const distanceFromBottom = list.scrollHeight - list.scrollTop - list.clientHeight;
      isUserPinnedToBottomRef.current = distanceFromBottom <= 24;
    };
    list.addEventListener('scroll', handleScroll);
    handleScroll();
    return () => {
      list.removeEventListener('scroll', handleScroll);
    };
  }, []);

  const groupedMessages = useMemo(() => {
    return (allMessages ?? []).reduce<Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }>>(
      (acc, msg) => {
        const last = acc[acc.length - 1];
        if (last && last.sender === msg.sender) {
          last.items.push(msg);
        } else {
          acc.push({ sender: msg.sender, items: [msg] });
        }
        return acc;
      },
      [],
    );
  }, [allMessages]);

  const formatTimestamp = useCallback((value?: string) => {
    if (!value) return '';
    const parsed = new Date(value);
    if (Number.isNaN(parsed.getTime())) return '';
    return parsed.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }, []);

  const handleSend = useCallback(() => {
    const trimmed = draft.trim();
    if (!trimmed) return;
    const outgoing = { sender: props.currentUser, text: trimmed, timestamp: new Date().toISOString() };
    setAllMessages((prev) => [...prev, outgoing]);
    sendMessage({ text: trimmed, timestamp: outgoing.timestamp || new Date().toISOString() });
    setDraft('');
  }, [draft, props.currentUser, sendMessage]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
        <Stack gap="var(--ggui-spacing-4)">
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3} color="var(--ggui-color-onSurface)">{props.title}</Heading>
              {typingState?.active === true && typingState?.sender && typingState.sender !== props.currentUser ? (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {`${typingState.sender} is typing...`}
                </Text>
              ) : null}
            </Stack>
            <Badge variant="primary">{props.participantCount} participants</Badge>
          </Row>

          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Box
              ref={listRef}
              style={{
                height: '60vh',
                overflowY: 'auto',
                paddingRight: 'var(--ggui-spacing-2)',
              }}
            >
              <Stack gap="var(--ggui-spacing-3)">
                {groupedMessages.length === 0 ? (
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" align="center">
                    No messages yet
                  </Text>
                ) : (
                  groupedMessages.map((group, groupIndex) => {
                    const isOwn = group.sender === props.currentUser;
                    return (
                      <Stack key={`${group.sender || 'unknown'}-${groupIndex}`} gap="var(--ggui-spacing-1)" align={isOwn ? 'end' : 'start'}>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{group.sender || 'Unknown'}</Text>
                        {group.items.map((item, index) => (
                          <Box
                            key={`${groupIndex}-${index}-${item.timestamp || 't'}`}
                            padding="var(--ggui-spacing-2)"
                            background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                            borderRadius="var(--ggui-shape-radius-md)"
                          >
                            <Stack gap="var(--ggui-spacing-1)">
                              <Text
                                variant="caption"
                                color={isOwn ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurfaceVariant)'}
                              >
                                {item.sender || 'Unknown'}
                              </Text>
                              <Text
                                variant="bodySmall"
                                color={isOwn ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurface)'}
                              >
                                {item.text || ''}
                              </Text>
                              <Text
                                variant="caption"
                                color={isOwn ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurfaceVariant)'}
                                align={isOwn ? 'right' : 'left'}
                              >
                                {formatTimestamp(item.timestamp)}
                              </Text>
                            </Stack>
                          </Box>
                        ))}
                      </Stack>
                    );
                  })
                )}
              </Stack>
            </Box>
          </Box>

          <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

          <Row gap="var(--ggui-spacing-2)" align="end">
            <Box style={{ flex: 1 }}>
              <Input
                label="Message"
                placeholder="Type a message..."
                value={draft}
                onChange={setDraft}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Button
              variant="primary"
              onClick={handleSend}
              disabled={!draft.trim()}
            >
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

