}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [stockMap, setStockMap] = useState<Record<string, { symbol: string; name: string; price: number; change: number; changePercent: number }>>({});
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [now, setNow] = useState<Date>(new Date());
  const [flashMap, setFlashMap] = useState<Record<string, boolean>>({});

  useEffect(() => {
    const nextMap: Record<string, { symbol: string; name: string; price: number; change: number; changePercent: number }> = {};
    (props.stocks || []).forEach((stock, index) => {
      const key = stock.symbol || `stock-${index}`;
      nextMap[key] = {
        symbol: stock.symbol || '—',
        name: stock.name || 'Unknown Company',
        price: typeof stock.price === 'number' ? stock.price : 0,
        change: typeof stock.change === 'number' ? stock.change : 0,
        changePercent: typeof stock.changePercent === 'number' ? stock.changePercent : 0,
      };
    });
    setStockMap(nextMap);
  }, [props.stocks]);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) {
      return;
    }
    const symbolKey = priceUpdate.latest.symbol;
    let updated = false;
    setStockMap((prev) => {
      const existing = prev[symbolKey];
      updated = true;
      return {
        ...prev,
        [symbolKey]: {
          symbol: symbolKey || existing?.symbol || '—',
          name: existing?.name || symbolKey || 'Unknown Company',
          price: typeof priceUpdate.latest?.price === 'number' ? priceUpdate.latest.price : existing?.price ?? 0,
          change: typeof priceUpdate.latest?.change === 'number' ? priceUpdate.latest.change : existing?.change ?? 0,
          changePercent: typeof priceUpdate.latest?.changePercent === 'number' ? priceUpdate.latest.changePercent : existing?.changePercent ?? 0,
        },
      };
    });
    if (!updated) {
      return;
    }
    setLastUpdated(priceUpdate.latest && 'timestamp' in priceUpdate.latest && (priceUpdate.latest as unknown as { timestamp?: string }).timestamp ? new Date((priceUpdate.latest as unknown as { timestamp?: string }).timestamp as string) : new Date());
    setFlashMap((prev) => ({ ...prev, [symbolKey]: true }));
  }, [priceUpdate.latest]);

  useEffect(() => {
    if (!marketStatus.latest) {
      return;
    }
    setLastUpdated(marketStatus.latest.timestamp ? new Date(marketStatus.latest.timestamp) : new Date());
  }, [marketStatus.latest]);

  useEffect(() => {
    const timer = setInterval(() => {
      setNow(new Date());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const active = Object.keys(flashMap).filter((key) => flashMap[key]);
    if (active.length === 0) return;
    const timeout = setTimeout(() => {
      setFlashMap((prev) => {
        const next = { ...prev };
        active.forEach((key) => {
          next[key] = false;
        });
        return next;
      });
    }, 700);
    return () => clearTimeout(timeout);
  }, [flashMap]);

  const stockList = useMemo(() => Object.values(stockMap), [stockMap]);
  const currentStatus = marketStatus.latest?.status || 'open';
  const statusVariant = currentStatus === 'open' ? 'success' : currentStatus === 'closed' ? 'error' : 'warning';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" border shadow="sm" radius="lg">
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={1} color="var(--ggui-color-onSurface)">Market Watch</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated: {new Date(lastUpdated.getTime() + (now.getTime() - lastUpdated.getTime())).toLocaleTimeString()}
              </Text>
            </Stack>
            <Badge variant={statusVariant}>
              {currentStatus}
            </Badge>
          </Row>
        </Card>

        {stockList.length === 0 ? (
          <Alert variant="info" title="No stock data">
            No stocks are available yet. Waiting for market data stream updates.
          </Alert>
        ) : (
          <CardGrid columns={{ sm: 1, lg: 3 }} gap={16}>
            {stockList.map((stockItem, index) => {
              const isPositive = stockItem.change >= 0;
              const toneColor = isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';
              const arrow = isPositive ? '▲' : '▼';
              const key = stockItem.symbol || `stock-${index}`;
              return (
                <Card
                  key={key}
                  padding="var(--ggui-spacing-4)"
                  border
                  shadow="sm"
                  radius="lg"
                >
                  <Box
                    padding="var(--ggui-spacing-2)"
                    background={flashMap[key] ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surfaceVariant)'}
                    borderRadius="var(--ggui-shape-radius-md)"
                    style={{ animation: flashMap[key] ? 'ggui-fadeIn 350ms ease-out' : 'none' }}
                  >
                    <Stack gap="var(--ggui-spacing-2)">
                      <Row justify="between" align="center">
                        <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface)">
                          {stockItem.symbol}
                        </Text>
                        <Badge variant={isPositive ? 'success' : 'error'}>
                          {arrow} {Math.abs(stockItem.changePercent).toFixed(2)}%
                        </Badge>
                      </Row>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" truncate>
                        {stockItem.name}
                      </Text>
                      <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">
                        ${stockItem.price.toFixed(2)}
                      </Text>
                      <Row justify="between" align="center">
                        <Text variant="label" color={toneColor}>
                          {isPositive ? '+' : ''}{stockItem.change.toFixed(2)}
                        </Text>
                        <Text variant="label" color={toneColor}>
                          {arrow} {isPositive ? '+' : ''}{stockItem.changePercent.toFixed(2)}%
                        </Text>
                      </Row>
                    </Stack>
                  </Box>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>

  );
}

