    setEmail(props.initialProfile?.email || '');
    setAvatar(props.initialProfile?.avatar || (availableAvatars[0] || '👤'));
    setRole(props.initialProfile?.role || '');
    setEmailNotifications(Boolean(props.initialProfile?.emailNotifications));
    setTheme(props.initialProfile?.theme === 'dark' ? 'dark' : 'light');
  }, [props.initialProfile, availableAvatars]);

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const stepOneValid = useMemo(() => name.trim().length > 0 && email.trim().length > 0 && emailValid && avatar.trim().length > 0, [name, email, emailValid, avatar]);
  const stepTwoValid = useMemo(() => theme === 'light' || theme === 'dark', [theme]);
  const canGoNext = step === 1 ? stepOneValid : true;
  const handleNext = useCallback(() => {
    if (step < 3) {
      if (!canGoNext) {
        setShowValidation(true);
        return;
      }
      setShowValidation(false);
      setStep(step + 1);
    }
  }, [step, canGoNext]);

  const handleBack = useCallback(() => {
    if (step > 1) {
      setShowValidation(false);
      setStep(step - 1);
    }
  }, [step]);

  const handleComplete = useCallback(() => {
    if (!stepOneValid || !stepTwoValid) {
      return;
    }
    const payload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    };
    complete(payload);
    if (typeof (props as unknown as { onComplete?: (data: ActionCompletePayload) => void }).onComplete === 'function') {
      (props as unknown as { onComplete?: (data: ActionCompletePayload) => void }).onComplete?.(payload);
    }
  }, [complete, stepOneValid, stepTwoValid, name, email, avatar, role, emailNotifications, theme, props]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Setup</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={(step / 3) * 100} max={100} size="md" />
            <Row gap="var(--ggui-spacing-2)">
              <Badge variant={step >= 1 ? 'primary' : 'default'}>1. Profile</Badge>
              <Badge variant={step >= 2 ? 'primary' : 'default'}>2. Preferences</Badge>
              <Badge variant={step >= 3 ? 'primary' : 'default'}>3. Review</Badge>
            </Row>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Box>
            {step === 1 && (
              <Box
                style={{
                  animation: 'ggui-fadeIn 200ms ease-out',
                }}
              >
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Profile Setup</Heading>
                  <Input
                    label="Name"
                    value={name}
                    onChange={setName}
                    placeholder="Enter your name"
                    required
                    error={showValidation && name.trim().length === 0 ? 'Name is required.' : undefined}
                  />
                  <Input
                    label="Email"
                    type="email"
                    value={email}
                    onChange={setEmail}
                    placeholder="you@example.com"
                    required
                    error={showValidation && (email.trim().length === 0 || !emailValid) ? 'Enter a valid email address.' : undefined}
                  />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Choose an avatar</Text>
                    <Row gap="var(--ggui-spacing-2)" wrap>
                      {availableAvatars.map((option) => (
                        <Card
                          key={option}
                          as={Clickable}
                          onClick={() => setAvatar(option)}
                          padding="var(--ggui-spacing-3)"
                          border
                          shadow="none"
                          radius="md"
                          style={{
                            borderColor: avatar === option ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                            background: avatar === option ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                            transition: 'all 200ms ease',
                          }}
                        >
                          <Text size="2xl" align="center">{option}</Text>
                        </Card>
                      ))}
                    </Row>
                  </Stack>
                </Stack>
              </Box>
            )}

            {step === 2 && (
              <Box
                style={{
                  animation: 'ggui-fadeIn 200ms ease-out',
                }}
              >
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Preferences</Heading>
                  <Select
                    label="Role"
                    value={role}
                    onChange={setRole}
                    options={availableRoles.map((item) => ({ value: item, label: item }))}
                    placeholder="Select your role"
                  />
                  <Toggle
                    label="Email notifications"
                    checked={emailNotifications}
                    onChange={setEmailNotifications}
                  />
                  <Toggle
                    label="Dark theme"
                    checked={theme === 'dark'}
                    onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  />
                </Stack>
              </Box>
            )}

            {step === 3 && (
              <Box
                style={{
                  animation: 'ggui-fadeIn 200ms ease-out',
                }}
              >
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Review & Confirm</Heading>
                  <Card padding="var(--ggui-spacing-4)" shadow="none" border radius="md">
                    <Stack gap="var(--ggui-spacing-3)">
                      <Row align="center" gap="var(--ggui-spacing-2)">
                        <Text variant="label">Avatar:</Text>
                        <Text size="2xl">{avatar}</Text>
                      </Row>
                      <Divider margin="var(--ggui-spacing-2)" />
                      <Row justify="between"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Row>
                      <Row justify="between"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Row>
                      <Row justify="between"><Text variant="label">Role</Text><Text>{role || '-'}</Text></Row>
                      <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                      <Row justify="between"><Text variant="label">Theme</Text><Text>{theme === 'dark' ? 'Dark' : 'Light'}</Text></Row>
                    </Stack>
                  </Card>
                </Stack>
              </Box>
            )}
          </Box>

          <Divider margin="var(--ggui-spacing-4)" />
          <Row justify="between" align="center">
            <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
              Back
            </Button>
            <Row gap="var(--ggui-spacing-2)">
              {step < 3 ? (
                <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
                  Next
                </Button>
              ) : (
                <>
                  <Button variant="outline" onClick={() => setStep(2)}>
                    Go Back
                  </Button>
                  <Button variant="primary" onClick={handleComplete} disabled={!stepOneValid || !stepTwoValid}>
                    Complete Setup
                  </Button>
                </>
              )}
            </Row>
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}
